Logger log = Logger.getLogger("setApprovalSet");


Map thirdOwnerToSet = new LinkedHashMap();
ManagedAttribute ma = new ManagedAttribute();

public Map getEntitlementApprovers(ApprovalItem item)
{

  Map additionalApprovers = new HashMap();

  String appName = item.getApplicationName();						 
  String entName = item.getName();
  List vals = item.getValueList();
  String entVal = (String) vals.get(0);

  QueryOptions qo = new QueryOptions();
  qo.addFilter(Filter.eq("application.name", appName));
  qo.addFilter(Filter.eq("attribute", entName));
  qo.addFilter(Filter.eq("value", entVal));

  Iterator it = context.search(ManagedAttribute.class, qo, "id");
  while(it.hasNext()) {
    String id = it.next()[0];
    ma = context.getObject(ManagedAttribute.class, id);

    //If additional approvers are needed, repeat the below logic 
    if(ma.getAttribute("3rdLvlApprover") != null) {

      String approverID = (String) ma.getAttribute("3rdLvlApprover");
      Identity idn = context.getObject(Identity.class, approverID);
      String approverName = idn.getName();
      additionalApprovers.put("3rdLevelApprover", approverName);
    }
  }

  return additionalApprovers;	
}

private void prepareApprovalLists(Map itemApprovers, ApprovalItem item)
{

  if(itemApprovers != null)
  {

    //If additional approvers are needed, repeat the below logic
    if(itemApprovers.get("3rdLevelApprover") != null)
    {
      String approver = itemApprovers.get("3rdLevelApprover");

      ApprovalSet set = thirdOwnerToSet.get(approver);

      if(set == null)
        set = new ApprovalSet();

      set.add(item);

      thirdOwnerToSet.put(approver, set);

    }
  }
}

newApprovals = new ArrayList();
