if(approvalSet != null)
{

  for(ApprovalItem item : approvalSet.getItems()) 
  {
    if(item.getOperation().equals("Remove"))
    {          

      item.approve();
      item.setState(WorkItem.State.Finished);
      if (newApprovals.size() == 2){

        newApprovals.remove(1);
      }
      newApprovals.remove(0);
      approval.setComplete(true);

      return newApprovals;
    }
    String appName = item.getApplication();
    if ("IIQ".compareTo(appName) == 0)
    {
      if (("detectedRoles".equals(item.getName())) || ("assignedRoles".equals(item.getName())))
      {
        continue;
      }
    }
    else
    {
      Map entApprovers = getEntitlementApprovers(item);
      prepareApprovalLists(entApprovers, item);
    }					
  }

  IdentityApprovalGenerator identityApprovalGenerator = new IdentityApprovalGenerator(wfcontext);
  if (thirdOwnerToSet != null) 
  {
    newApprovals.addAll(identityApprovalGenerator.buildApprovalsFromMap(thirdOwnerToSet, "Owner"));

  }


  if (ma.getAttribute("noOwnerApprover") != null && ma.getAttribute("noOwnerApprover") == true) 
  {

    if(newApprovals!=null)
    {
      if(newApprovals.size()!=0 && newApprovals.size()>0 )
      {

        if(newApprovals.size() == 2)
        {

          newApprovals.remove(1);

        }
        else
        {



          for(ApprovalItem item : approvalSet.getItems()) 
          {

            item.approve();
            item.setState(WorkItem.State.Finished);

          }
          newApprovals.remove(0);
          approval.setComplete(true);
          newApprovals.add(approval);
        }
      }
    }
  }
}

if(newApprovals.size()>0)
return newApprovals;
